# Ajouter des données
p.line([1, 2, 3, 4, 5], [6, 7, 2, 4, 5], line_width=2, legend_label="Ligne", line_color="blue")
p.circle([1, 2, 3, 4, 5], [6, 7, 2, 4, 5], size=10, color="red", alpha=0.5)

# Obtenir le script et le div pour l'intégration
script, div = components(p)

# Générer le fichier HTML
